+        input.push('!');
+
+        let start = std::time::Instant::now();
+        let result = re.find(&input);
+        let elapsed = start.elapsed();
+
+        assert!(result.is_none(), "pathological find should return None");
+        assert!(
+            elapsed < std::time::Duration::from_millis(50),
